import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.DGzMGr_a.js";const m=JSON.parse('{"title":"muthr","description":"","frontmatter":{},"headers":[],"relativePath":"muthr/index.md","filePath":"muthr/index.md","lastUpdated":null}'),i={name:"muthr/index.md"};function l(n,e,s,c,d,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="muthr" tabindex="-1">muthr <a class="header-anchor" href="#muthr" aria-label="Permalink to &quot;muthr&quot;">​</a></h1><p>muthr is a zero-trust orchestrator for local AI on Apple Silicon. It runs inference engines on the host, isolates agent runtimes inside per-project containers, and provides stable service endpoints for MCP and search tooling.</p><p>If you like Unix and POSIX design principles, muthr should feel familiar:</p><ul><li>clear subcommands for discrete lifecycle domains</li><li>scriptable output (<code>text</code>, <code>json</code>, <code>ndjson</code>)</li><li>explicit defaults and explicit overrides</li><li>safe behavior when context is missing or unsafe</li></ul><h2 id="why-this-exists" tabindex="-1">Why this exists <a class="header-anchor" href="#why-this-exists" aria-label="Permalink to &quot;Why this exists&quot;">​</a></h2><p>Running AI agents directly on your host is high-risk. Modern agent stacks execute package installers, shell commands, generated scripts, and network clients with broad filesystem access. A single compromised dependency, malicious prompt chain, or unsafe tool invocation can lead to credential leakage or host compromise.</p><p>muthr&#39;s core value is practical risk reduction with low operational friction:</p><ul><li>isolate agent execution into sandbox containers</li><li>preserve host-only assets outside container mounts</li><li>gate runtime context with explicit env contracts</li><li>keep lifecycle operations observable and auditable</li></ul><h2 id="core-model" tabindex="-1">Core model <a class="header-anchor" href="#core-model" aria-label="Permalink to &quot;Core model&quot;">​</a></h2><ol><li><strong>Host inference runtime</strong><ul><li><code>mlxcel-server</code> or <code>llama-server</code> managed by <code>muthr engine</code></li></ul></li><li><strong>Persistent services plane</strong><ul><li><code>muthr-services</code> + <code>muthr-searxng</code> managed by <code>muthr services</code></li></ul></li><li><strong>Per-project sandbox</strong><ul><li>one container per project directory, managed by <code>muthr sandbox</code></li></ul></li></ol><p>The default <code>muthr run</code> path boots engine + services, then you enter project sandboxes as needed.</p><h2 id="read-next" tabindex="-1">Read next <a class="header-anchor" href="#read-next" aria-label="Permalink to &quot;Read next&quot;">​</a></h2><ol><li><a href="/muthr/quickstart">Quickstart</a></li><li><a href="/muthr/commands">Commands</a></li><li><a href="/muthr/sandbox-architecture">Sandbox Architecture</a></li><li><a href="/muthr/security">Security</a></li></ol><h2 id="acknowledgements" tabindex="-1">Acknowledgements <a class="header-anchor" href="#acknowledgements" aria-label="Permalink to &quot;Acknowledgements&quot;">​</a></h2><p>muthr builds on excellent open-source foundations:</p><ul><li><a href="https://github.com/ggml-org/llama.cpp" target="_blank" rel="noreferrer">llama.cpp</a></li><li><a href="https://github.com/lablup/mlxcel" target="_blank" rel="noreferrer">mlxcel</a></li><li><a href="https://github.com/apple/container" target="_blank" rel="noreferrer">Apple container</a></li></ul>',16)])])}const p=t(i,[["render",l]]);export{m as __pageData,p as default};
